# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3
import json

QUEUE_NAME = "your-queue-name"
AWS_REGION = "us-west-2"

sqs = boto3.client('sqs', region_name=AWS_REGION)

def publish_message(message):
    response = sqs.send_message(
        QueueUrl=QUEUE_NAME,
        MessageBody=json.dumps(message),
        MessageAttributes={
            'email': {
                'DataType': 'String',
                'StringValue': "your-email@example.com"
            },
            'phoneNumber': {
                'DataType': 'String',
                'StringValue': "+1234567890"
            },
            'address': {
                'DataType': 'String',
                'StringValue': "123 Main St, Anytown, USA"
            }
        }
    )

    print(f"Sent message: {response['MessageId']}")

# Placeholder for your user data
user_data = {
    "email": "your-email@example.com",
    "phoneNumber": "+1234567890",
    "address": "123 Main St, Anytown, USA"
}

publish_message(user_data)